const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const end = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);
const todayStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, '0');
const d = String(now.getDate()).padStart(2, '0');
const afterDate = y + '/' + m + '/' + d;
return { timeMin: start.toISOString(), timeMax: end.toISOString(), today: todayStr, afterDate };

let emailData = '';
const emailResp = $.steps.fetchEmails.response;
const messages = emailResp.messages || emailResp.data || [];
let emailCount = 0;
if (Array.isArray(messages)) {
  messages.slice(0, 20).forEach((msg, i) => {
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    const getH = (n) => { const h = headers.find(h => h.name && h.name.toLowerCase() === n.toLowerCase()); return h ? h.value : ''; };
    emailData += (i + 1) + '. From: ' + (getH('From') || msg.from || 'Unknown') + ' | Subject: ' + (getH('Subject') || msg.subject || '(no subject)') + ' | ' + (msg.snippet || '').slice(0, 150) + '\n';
    emailCount++;
  });
}

let calendarData = '';
const calResp = $.steps.fetchCalendar.response;
const events = calResp.items || calResp.data || [];
let eventCount = 0;
if (Array.isArray(events)) {
  events.forEach((e, i) => {
    const start = e.start ? (e.start.dateTime || e.start.date || '') : '';
    calendarData += (i + 1) + '. ' + (e.summary || '(no title)') + ' at ' + start;
    if (e.location) calendarData += ' | Location: ' + e.location;
    const attendees = (e.attendees || []).map(a => a.email).join(', ');
    if (attendees) calendarData += ' | Attendees: ' + attendees;
    calendarData += '\n';
    eventCount++;
  });
}

return { emailData, emailCount, calendarData, eventCount };

const d = $.steps.compileData.output;
const today = $.steps.getDateBounds.output.today;

let prompt = 'You are a world-class executive personal assistant. Create a comprehensive daily briefing for ' + today + '.

';
prompt += '=== UNREAD EMAILS (' + d.emailCount + ') ===
' + (d.emailData || 'No unread emails.') + '

';
prompt += '=== CALENDAR EVENTS (' + d.eventCount + ') ===
' + (d.calendarData || 'No events today.') + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Create a prioritized daily briefing
';
prompt += '- Highlight conflicts or overlaps in calendar
';
prompt += '- Flag urgent emails that need immediate attention
';
prompt += '- Suggest an optimal schedule for the day
';
prompt += '- Identify any follow-ups needed

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "greeting": "Good morning brief",
';
prompt += '  "topPriorities": ["priority 1", "priority 2", "priority 3"],
';
prompt += '  "emailHighlights": [{ "from": "sender", "subject": "subj", "urgency": "high/medium/low", "action": "what to do" }],
';
prompt += '  "schedule": [{ "time": "9:00 AM", "activity": "what", "prep": "how to prepare" }],
';
prompt += '  "conflicts": ["any scheduling conflicts"],
';
prompt += '  "followUps": ["things to follow up on"],
';
prompt += '  "overallSummary": "2-3 sentence day overview"
';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { greeting: '', topPriorities: [], emailHighlights: [], schedule: [], conflicts: [], followUps: [], overallSummary: raw }; }

const ai = $.steps.parseAI.output;
const d = $.steps.compileData.output;
const today = $.steps.getDateBounds.output.today;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Briefing - ' + today, emoji: true } });

if (ai.greeting) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.greeting } });
}

blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails:*\n' + d.emailCount + ' unread' },
  { type: 'mrkdwn', text: '*Events:*\n' + d.eventCount + ' today' }
] });
blocks.push({ type: 'divider' });

const summary = (ai.overallSummary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:*\n' + summary } });

if (ai.topPriorities && ai.topPriorities.length > 0) {
  blocks.push({ type: 'divider' });
  let pText = '*Top Priorities:*\n';
  ai.topPriorities.forEach((p, i) => { pText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: pText.slice(0, 1800) } });
}

if (ai.schedule && ai.schedule.length > 0) {
  blocks.push({ type: 'divider' });
  let sText = '*Suggested Schedule:*\n';
  ai.schedule.slice(0, 10).forEach(s => {
    sText += '*' + s.time + '* - ' + s.activity;
    if (s.prep) sText += ' (' + s.prep + ')';
    sText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sText.slice(0, 1800) } });
}

if (ai.emailHighlights && ai.emailHighlights.length > 0) {
  blocks.push({ type: 'divider' });
  let eText = '*Urgent Emails:*\n';
  ai.emailHighlights.slice(0, 5).forEach(e => {
    eText += '  - *' + (e.subject || 'No subject') + '* from ' + (e.from || 'Unknown') + ' [' + (e.urgency || 'medium').toUpperCase() + ']\n';
    if (e.action) eText += '    _Action: ' + e.action + '_\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: eText.slice(0, 1800) } });
}

if (ai.conflicts && ai.conflicts.length > 0) {
  blocks.push({ type: 'divider' });
  let cText = '*Conflicts/Warnings:*\n';
  ai.conflicts.forEach((c, i) => { cText += (i + 1) + '. ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: cText.slice(0, 1800) } });
}

if (ai.followUps && ai.followUps.length > 0) {
  blocks.push({ type: 'divider' });
  let fText = '*Follow-Ups:*\n';
  ai.followUps.forEach((f, i) => { fText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Calendar + Claude AI | One CLI' }] });

const fallbackText = 'Daily Briefing: ' + d.emailCount + ' emails, ' + d.eventCount + ' events - ' + (ai.overallSummary || '').slice(0, 100);
return { blocks, fallbackText };
